You could even write your own subclass:

```python
class Curve2D(bezier.Curve):

    _x_curve = None
    _y_curve = None

    def __init__(self, *args, **kwargs):
        super(Curve2D, self).__init__(*args, **kwargs)
        if self._dimension != 2:
            raise ValueError('Bad dimension')

    @property
    def x_curve(self):
        # Lazily compute / store this.
        if self._x_curve is None:
            self._x_curve = bezier.Curve(self._nodes[:, [0]], self._degree)
        return self._x_curve

    @property
    def y_curve(self):
        # Lazily compute / store this.
        if self._y_curve is None:
            self._y_curve = bezier.Curve(self._nodes[:, [1]], self._degree)
        return self._y_curve

    def locate_x(self, value):
        point1d = np.asfortranarray([[value]])
        return self.x_curve.locate(point1d)

    def locate_y(self, value):
        point1d = np.asfortranarray([[value]])
        return self.y_curve.locate(point1d)
```

