The following code can be used to calculate the predecessors and successors

```
def get_all_predecessors(cfg, node):
	ret = set()

	def __predecessors(res, cfg, node):
		ps = cfg.graph.predecessors(node)

		for p in ps:
			if p in ret:
				continue

			res.add(p)
			__predecessors(res, cfg, p)

	__predecessors(ret, cfg, node)

	return ret

def get_all_successors(cfg, node):
	ret = set()

	def __successors(res, cfg, node):
		ss = cfg.graph.successors(node)
		for s in ss:
			if s in res:
				continue

			res.add(s)
			__successors(res, cfg, s)

	__successors(ret, cfg, node)

	return ret
```

